/** Computes the next generation of live cells per Conway's Game of Life rules. */
export function nextGeneration(liveCells: LiveCell[]): LiveCell[] {
  const key = (x: number, y: number) => `${x},${y}`;
  const liveCellKeys = new Set(liveCells.map(([x, y]) => key(x, y)));
  const neighborsOf = ([x, y]: LiveCell): LiveCell[] =>
    NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
  const liveNeighborCount = (cell: LiveCell) =>
    neighborsOf(cell).filter(([nx, ny]) => liveCellKeys.has(key(nx, ny))).length;
  const survives = (cell: LiveCell) => {
    const n = liveNeighborCount(cell);
    return n === 2 || n === 3;
  };
  const deadNeighbors = new Map<string, LiveCell>();
  for (const cell of liveCells) {
    for (const neighbor of neighborsOf(cell)) {
      const k = key(neighbor[0], neighbor[1]);
      if (!liveCellKeys.has(k)) deadNeighbors.set(k, neighbor);
    }
  }
  const births = [...deadNeighbors.values()].filter((cell) => liveNeighborCount(cell) === 3);
  return [...liveCells.filter(survives), ...births];
}

