/** Computes the next generation of live cells per Conway's Game of Life rules. */
export function nextGeneration(liveCells: LiveCell[]): LiveCell[] {
  const keyOf = ([x, y]: LiveCell) => `${x},${y}`;
  const liveKeys = new Set(liveCells.map(keyOf));

  const liveNeighborCounts = new Map<string, { cell: LiveCell; count: number }>();
  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const neighbor: LiveCell = [x + dx, y + dy];
      const k = keyOf(neighbor);
      const entry = liveNeighborCounts.get(k);
      if (entry) entry.count += 1;
      else liveNeighborCounts.set(k, { cell: neighbor, count: 1 });
    }
  }

  const isAliveNextGen = (key: string, count: number) =>
    count === 3 || (count === 2 && liveKeys.has(key));

  return [...liveNeighborCounts.entries()]
    .filter(([k, { count }]) => isAliveNextGen(k, count))
    .map(([, { cell }]) => cell);
}
